from dataclasses import dataclass, field
from datetime import date
from collections import defaultdict

@dataclass
class SeatAssignment:
    tool_id: str
    user_id: str
    team: str
    assigned_date: date
    last_active_date: Optional[date]
    is_active: bool

def find_reclaimable_seats(
    assignments: list[SeatAssignment],
    inactive_threshold_days: int = 30,
    as_of: date = None,
) -> list[SeatAssignment]:
    """Return seats where last_active_date is more than threshold days ago.""""
    if as_of is None:
        as_of = date.today()
    reclaimable = []
    for a in assignments:
        if not a.is_active:
            continue
        if a.last_active_date is None:
            # Never logged in — immediately reclaimable
            reclaimable.append(a)
        elif (as_of - a.last_active_date).days > inactive_threshold_days:
            reclaimable.append(a)
    return reclaimable

def build_seat_reclaim_report(
    assignments: list[SeatAssignment],
    cost_per_seat_monthly_usd: float,
    as_of: date = None,
) -> dict:
    reclaimable = find_reclaimable_seats(assignments, as_of=as_of)
    by_team: dict[str, list[SeatAssignment]] = defaultdict(list)
    for a in reclaimable:
        by_team[a.team].append(a)

    monthly_waste = len(reclaimable) * cost_per_seat_monthly_usd
    return {
        "reclaimable_seats": len(reclaimable),
        "monthly_waste_usd": round(monthly_waste, 2),
        "annual_waste_usd": round(monthly_waste * 12, 2),
        "by_team": {team: len(seats) for team, seats in by_team.items()},
        "never_logged_in": sum(1 for a in reclaimable if a.last_active_date is None),
    }

from dataclasses import dataclass
from datetime import date

@dataclass
class OptimizationOutcome:
    tool_id: str
    action_taken: str          # "seat_reduction" | "cancellation" | "tier_change" | "renegotiated"
    seats_before: int
    seats_after: int
    cost_before_usd: float
    cost_after_usd: float
    completed_date: date

    @property
    def annual_savings_usd(self) -> float:
        return self.cost_before_usd - self.cost_after_usd

    @property
    def savings_pct(self) -> float:
        if self.cost_before_usd == 0:
            return 0.0
        return self.annual_savings_usd / self.cost_before_usd

def summarise_optimisation_impact(outcomes: list[OptimizationOutcome]) -> dict:
    total_savings = sum(o.annual_savings_usd for o in outcomes)
    by_action: dict[str, float] = {}
    for o in outcomes:
        by_action[o.action_taken] = by_action.get(o.action_taken, 0) + o.annual_savings_usd
    return {
        "total_tools_optimized": len(outcomes),
        "total_annual_savings_usd": round(total_savings, 2),
        "savings_by_action": {k: round(v, 2) for k, v in by_action.items()},
        "avg_savings_pct": sum(o.savings_pct for o in outcomes) / len(outcomes) if outcomes else 0.0,
    }
